ruleToc.chapterName:
text
@js:
(() => {
  let cMatch = result.match(/.*第\s*([0-9零一二两三四五六七八九十百千万]+)\s*章\s*[\.，、：]*(\d+)?(.*)/);

  if (cMatch) {
    let tContent = cMatch[3].trim();
    let idx = java.toNumChapter(result);
    let cNum = cMatch[2] || parseInt(String(idx).replace(/[^0-9]/g, ''), 10);

    return `第${cNum}章 ${tContent}`;
  } else {
    let nMatch = result.match(/(\d+)/);
    if (nMatch) {
      let tContent = /^\d+$/.test(result) ? result : result.replace(/.*?\d+\s*[\.，、：]*(.+)/, '$1').trim();
      let cNum = nMatch[1].replace(/^0+(?=[1-9])/g, '');
      return /^\d+$/.test(result) ? `第${cNum}章` : `第${cNum}章 ${tContent}`;
    } else {
      return result;
    }
  }
})();

